CREATE OR REPLACE FUNCTION fpa_fin_pay_type ( as_vourcher_no text ) RETURNS SC_FIN_VOURCHER_DETAIL.PAY_TYPE%TYPE AS $body$
DECLARE

  ls_pay_type sc_fin_vourcher_detail.pay_type%type;
  li_rc integer := 0;

BEGIN

  ls_pay_type := 'C';
  select count( 1 ) into STRICT li_rc
  from sc_fin_vourcher_detail
  where 1=1
  and vourcher_no = as_vourcher_no
  and pay_type  = ls_pay_type;

  if li_rc > 0 then
    return ls_pay_type;
  end if;

  ls_pay_type := 'Q';
  select count( 1 ) into STRICT li_rc
  from sc_fin_vourcher_detail
  where 1=1
  and vourcher_no = as_vourcher_no
  and pay_type  = ls_pay_type;
  if li_rc > 0 then
    return ls_pay_type;
  end if;

  ls_pay_type := 'T';
  return ls_pay_type;


exception when others then return 'C';
END;
$body$
